# Security: Query depth limiting
def get_query_depth(query_string):
    depth = 0
    max_depth = 0
    for char in query_string:
        if char == '{':
            depth += 1
            max_depth = max(max_depth, depth)
        elif char == '}':
            depth -= 1
    return max_depth

# Security: Query complexity analysis
def estimate_query_complexity(query_string):
    # Simple heuristic: count field selections
    complexity = query_string.count('\n')
    return complexity

# Security: Rate limiting storage (in-memory for demo)
request_counts = {}

def check_rate_limit(identifier):
    import time
    current_time = int(time.time())
    window = 60  # 1 minute window
    max_requests = 100
    
    if identifier not in request_counts:
        request_counts[identifier] = []
    
    # Clean old requests
    request_counts[identifier] = [
        ts for ts in request_counts[identifier] 
        if current_time - ts < window
    ]
    
    if len(request_counts[identifier]) >= max_requests:
        return False
    
    request_counts[identifier].append(current_time)
    return True

