@app.route("/graphql", methods=["POST"])
def graphql_server():
    # Security: Rate limiting
    client_ip = request.remote_addr
    if not check_rate_limit(client_ip):
        return jsonify({"error": "Rate limit exceeded"}), 429
    
    data = request.get_json()
    
    # Security: Validate request
    if not data or "query" not in data:
        return jsonify({"error": "Invalid request"}), 400
    
    query_string = data.get("query", "")
    
    # Security: Query depth limiting (max depth 5)
    if get_query_depth(query_string) > 5:
        return jsonify({"error": "Query depth exceeds maximum allowed"}), 400
    
    # Security: Query complexity limiting
    if estimate_query_complexity(query_string) > 200:
        return jsonify({"error": "Query too complex"}), 400
    
    # Security: Disable introspection in production
    if "__schema" in query_string or "__type" in query_string:
        # In production, you might want to disable this
        pass
    
    # Security: Prevent batch queries abuse
    if isinstance(data, list):
        if len(data) > 5:  # Limit batch size
            return jsonify({"error": "Too many queries in batch"}), 400
    
    # Add current_user to context
    context = {
        "request": request,
        "current_user": getattr(request, "current_user", None)
    }
    
    success, result = graphql_sync(
        schema,
        data,
        context_value=context,
        debug=app.debug
    )
    
    status_code = 200 if success else 400
    return jsonify(result), status_code

